insert into modules (product_id, stage_group, title, teaching_text, focus_items, sort_order) values
  ((select id from products where slug='business-launch'), 'Strategy', 'Vision & Purpose', 'Every business needs one clear reason to exist before it needs anything else.', '["Define why your business exists.", "Create a compelling vision and mission.", "Identify the problem you''re solving.", "Establish your long-term direction."]'::jsonb, 1),
  ((select id from products where slug='business-launch'), 'Strategy', 'Business Idea', 'Put the idea into plain words so you — and anyone else — can see exactly what you''re building.', '["Describe your business concept.", "Define your products or services.", "Explain the value you provide.", "Identify what makes your idea unique."]'::jsonb, 2),
  ((select id from products where slug='business-launch'), 'Strategy', 'Market Research', 'A little research now saves you from building something nobody''s actually waiting for.', '["Understand your industry.", "Analyse competitors.", "Identify market trends.", "Validate customer demand."]'::jsonb, 3),
  ((select id from products where slug='business-launch'), 'Strategy', 'Target Customer', 'The clearer you are on who you''re serving, the easier every other decision becomes.', '["Define your ideal customer.", "Understand customer needs.", "Build customer personas.", "Identify buying behaviours."]'::jsonb, 4),
  ((select id from products where slug='business-launch'), 'Strategy', 'Business Model', 'This is simply how money moves — what you charge for, and why it holds together.', '["Explain how your business generates revenue.", "Identify key income streams.", "Understand pricing strategies.", "Create a sustainable model."]'::jsonb, 5),
  ((select id from products where slug='business-launch'), 'Brand', 'Brand Strategy', 'Your brand is the feeling people get when they think of you — decide that on purpose.', '["Define your brand identity.", "Establish your positioning.", "Develop your brand personality.", "Create a memorable customer experience."]'::jsonb, 6),
  ((select id from products where slug='business-launch'), 'Brand', 'Business Name', 'A good name is memorable, sayable, and free to use — in that order.', '["Brainstorm business names.", "Check availability.", "Consider trademarks.", "Select a name that reflects your brand."]'::jsonb, 7),
  ((select id from products where slug='business-launch'), 'Brand', 'Logo & Visual Identity', 'Your visuals should do the talking before you say a single word.', '["Create a professional logo.", "Choose colours and typography.", "Define brand guidelines.", "Build visual consistency."]'::jsonb, 8),
  ((select id from products where slug='business-launch'), 'Offer', 'Products & Services', 'Be specific about what you sell — vague offerings are hard to buy.', '["Define your offerings.", "Explain customer benefits.", "Create product descriptions.", "Plan future product development."]'::jsonb, 9),
  ((select id from products where slug='business-launch'), 'Offer', 'Pricing Strategy', 'Price is a decision about margin, not just what feels fair — get comfortable with both.', '["Calculate your costs.", "Set profitable prices.", "Understand margin and markup.", "Position your pricing competitively."]'::jsonb, 10),
  ((select id from products where slug='business-launch'), 'Growth', 'Marketing Strategy', 'Marketing at this stage is simple: tell the right people you exist, where they already are.', '["Build your marketing plan.", "Choose marketing channels.", "Define your messaging.", "Create customer awareness."]'::jsonb, 11),
  ((select id from products where slug='business-launch'), 'Growth', 'Sales Strategy', 'A sale is just a series of small yeses — map out how someone gets from curious to customer.', '["Develop your sales process.", "Understand your sales funnel.", "Generate leads.", "Convert enquiries into customers."]'::jsonb, 12),
  ((select id from products where slug='business-launch'), 'Operations', 'Operations Plan', 'This is the day-to-day machinery — write it down once so it doesn''t live only in your head.', '["Plan daily business activities.", "Identify suppliers and resources.", "Define business processes.", "Improve operational efficiency."]'::jsonb, 13),
  ((select id from products where slug='business-launch'), 'Operations', 'Financial Planning', 'You only need a handful of numbers to know if the business holds together.', '["Estimate startup costs.", "Forecast revenue and expenses.", "Understand cash flow.", "Plan for profitability."]'::jsonb, 14),
  ((select id from products where slug='business-launch'), 'Operations', 'Funding', 'Know what you need before you go looking for it — vague asks get vague answers.', '["Identify funding requirements.", "Explore finance options.", "Prepare investor information.", "Develop a funding strategy."]'::jsonb, 15),
  ((select id from products where slug='business-launch'), 'Operations', 'Legal & Compliance', 'The unglamorous paperwork that protects everything else you''re building.', '["Choose a business structure.", "Register your business.", "Understand tax obligations.", "Ensure legal compliance."]'::jsonb, 16),
  ((select id from products where slug='business-launch'), 'Operations', 'Technology & Systems', 'The right tools save hours every week — pick systems that grow with you.', '["Select business software.", "Improve productivity.", "Manage information effectively.", "Build scalable systems."]'::jsonb, 17),
  ((select id from products where slug='business-launch'), 'Operations', 'Risk Assessment', 'A few minutes naming what could go wrong now beats being blindsided later.', '["Identify potential risks.", "Evaluate business threats.", "Develop contingency plans.", "Strengthen business resilience."]'::jsonb, 18),
  ((select id from products where slug='business-launch'), 'Launch & track', 'Launch Plan', 'Perfect is the enemy of launched — pick a date and get something real in front of people.', '["Prepare for launch.", "Complete your checklist.", "Plan your first marketing campaign.", "Build launch momentum."]'::jsonb, 19),
  ((select id from products where slug='business-launch'), 'Launch & track', 'KPI Dashboard', 'A handful of numbers, checked weekly, tells you more than fifty checked never.', '["Define success metrics.", "Track business performance.", "Measure financial results.", "Monitor continuous improvement."]'::jsonb, 20),
  ((select id from products where slug='business-launch'), 'Launch & track', 'Resources', 'Templates and tools in one place, so you''re never rebuilding the wheel.', '["Access templates and tools.", "Download useful resources.", "Explore recommended reading.", "Continue your learning journey."]'::jsonb, 21);
